code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let inputs = [];
readline.on('line', line => {
    inputs.push(line);
});
readline.on('close', () => {
    let T = parseInt(inputs[i++]);
    while (T--) {
        let [N, K] = inputs[i++].split(' ').map(Number);
        console.log((K * (2 * N + 1) - N) % 1000000007);
    }
});

